script:
frappe.ui.form.on('Client Project Onboarding', {

    refresh: function(frm) {
        // Show Send Kickoff Email button
        if (!frm.is_new() && frm.doc.status === 'Kickoff Scheduled') {
            frm.add_custom_button('Send Kickoff Email', function() {
                send_kickoff_email(frm);
            });
        }
    },

    start_date: function(frm) {
        validate_start_date(frm);
    },

    status: function(frm) {
        if (frm.doc.status === 'Kickoff Scheduled') {
            if (!frm.doc.sow_attached) {
                frappe.msgprint({
                    title: 'SOW Required',
                    message: 'SOW must be attached before scheduling kickoff.',
                    indicator: 'red'
                });
                frm.set_value('status', 'Draft');
            }
        }
    },

    validate: function(frm) {
        // Validate start date
        if (frm.doc.start_date) {
            let today = frappe.datetime.get_today();
            if (frm.doc.start_date < today) {
                frappe.msgprint({
                    title: 'Invalid Start Date',
                    message: 'Start Date cannot be in the past.',
                    indicator: 'red'
                });
                frappe.validated = false;
            }
        }

        // Warn if no team members
        if (!frm.doc.team_members || frm.doc.team_members.length === 0) {
            frappe.msgprint({
                title: 'No Team Assigned',
                message: 'No team assigned. Are you sure you want to proceed?',
                indicator: 'orange'
            });
        }

        // Block if SOW not attached and status is Kickoff Scheduled
        if (frm.doc.status === 'Kickoff Scheduled' && !frm.doc.sow_attached) {
            frappe.msgprint({
                title: 'SOW Required',
                message: 'SOW must be attached before scheduling kickoff.',
                indicator: 'red'
            });
            frappe.validated = false;
        }
    }
});

function validate_start_date(frm) {
    if (frm.doc.start_date) {
        let today = frappe.datetime.get_today();
        if (frm.doc.start_date < today) {
            frappe.msgprint({
                title: 'Invalid Start Date',
                message: 'Start Date cannot be in the past.',
                indicator: 'red'
            });
            frm.set_value('start_date', '');
        }
    }
}

function send_kickoff_email(frm) {
    // Build team members list
    let team_list = '';
    if (frm.doc.team_members) {
        frm.doc.team_members.forEach(function(member) {
            team_list += '- ' + member.employee + ' (' + member.role + ')\n';
        });
    }

    let email_body = `Dear Team,

We are excited to announce the kickoff of project: ${frm.doc.project_name}

Client: ${frm.doc.client_name}
Project Type: ${frm.doc.project_type}
Start Date: ${frm.doc.start_date}
Project Manager: ${frm.doc.project_manager}
Tech Lead: ${frm.doc.tech_lead}

Team Members:
${team_list}

Please make sure to review the SOW and be ready for the kickoff meeting.

Best Regards,
${frm.doc.project_manager}`;

    frappe.prompt([
        {
            fieldname: 'email_body',
            fieldtype: 'Text Editor',
            label: 'Email Body',
            default: email_body
        },
        {
            fieldname: 'recipients',
            fieldtype: 'Data',
            label: 'Recipients (comma separated emails)',
        }
    ],
    function(values) {
        frappe.call({
            method: 'frappe.core.doctype.communication.email.make',
            args: {
                recipients: values.recipients,
                subject: 'Project Kickoff: ' + frm.doc.project_name,
                content: values.email_body,
                doctype: frm.doctype,
                name: frm.docname,
                send_email: 1
            },
            callback: function(r) {
                if (!r.exc) {
                    frappe.msgprint({
                        title: 'Success',
                        message: 'Kickoff email sent successfully!',
                        indicator: 'green'
                    });
                }
            }
        });
    },
    'Send Kickoff Email',
    'Send'
    );
}

frappe.ui.form.on('Performance Review', {
    refresh: function(frm) {
        let roles = frappe.user_roles;

        // Role-based field visibility
        if (!roles.includes('HR Manager') && !roles.includes('System Manager')) {
            frm.set_df_property('hr_comments', 'read_only', 1);
            frm.set_df_property('final_status', 'read_only', 1);
        }
        if (!roles.includes('Appraisal Manager') && !roles.includes('HR Manager') && !roles.includes('System Manager')) {
            frm.set_df_property('manager_comments', 'read_only', 1);
            frm.fields_dict['kpis'].grid.update_docfield_property('score', 'read_only', 1);
            frm.fields_dict['kpis'].grid.update_docfield_property('target', 'read_only', 1);
            frm.fields_dict['kpis'].grid.update_docfield_property('achieved', 'read_only', 1);
        }

        // Show color-coded rating message
        show_rating_message(frm);

        // Generate Appraisal Letter button
        if (!frm.is_new() && frm.doc.final_status !== 'Draft') {
            frm.add_custom_button('Generate Appraisal Letter', function() {
                frappe.call({
                    method: 'frappe.client.get',
                    args: { doctype: 'Performance Review', name: frm.docname },
                    callback: function(r) {
                        if (r.message) {
                            let doc = r.message;
                            let content = `
                                <h2>Appraisal Letter</h2>
                                <p><b>Employee:</b> ${doc.employee}</p>
                                <p><b>Review Period:</b> ${doc.review_period} ${doc.review_year}</p>
                                <p><b>Department:</b> ${doc.department}</p>
                                <p><b>Overall Score:</b> ${doc.overall_score}</p>
                                <p><b>Rating:</b> ${doc.rating}</p>
                                <p><b>Manager Comments:</b> ${doc.manager_comments || 'N/A'}</p>
                                <hr>
                                <p>This letter serves as an official record of your performance review.</p>
                            `;
                            frappe.msgprint({
                                title: 'Appraisal Letter',
                                message: content,
                                wide: true
                            });
                        }
                    }
                });
            });
        }
    },

    employee: function(frm) {
        if (frm.doc.employee) {
            frappe.db.get_value('Employee', frm.doc.employee, 'department', function(r) {
                if (r && r.department) {
                    frm.set_value('department', r.department);
                }
            });
        }
    }
});

frappe.ui.form.on('KPI Entry', {
    score: function(frm) {
        calculate_overall_score(frm);
    },
    kpis_remove: function(frm) {
        calculate_overall_score(frm);
    }
});

function calculate_overall_score(frm) {
    let kpis = frm.doc.kpis || [];
    if (kpis.length === 0) {
        frm.set_value('overall_score', 0);
        frm.set_value('rating', '');
        return;
    }

    let total = 0;
    let count = 0;
    kpis.forEach(function(kpi) {
        if (kpi.score) {
            total += kpi.score;
            count++;
        }
    });

    let avg = count > 0 ? Math.round((total / count) * 10) / 10 : 0;
    frm.set_value('overall_score', avg);

    let rating = '';
    if (avg >= 9) rating = 'Exceptional';
    else if (avg >= 7) rating = 'Exceeds Expectations';
    else if (avg >= 5) rating = 'Meets Expectations';
    else if (avg >= 3) rating = 'Needs Improvement';
    else rating = 'Unsatisfactory';

    frm.set_value('rating', rating);
    show_rating_message(frm);
}

function show_rating_message(frm) {
    if (!frm.doc.rating) return;

    let color = 'green';
    if (frm.doc.rating === 'Needs Improvement' || frm.doc.rating === 'Unsatisfactory') {
        color = 'red';
    } else if (frm.doc.rating === 'Meets Expectations') {
        color = 'orange';
    }

    frappe.show_alert({
        message: 'Rating: ' + frm.doc.rating,
        indicator: color
    }, 5);
}

frappe.ui.form.on('Monthly Payroll Run', {
    refresh: function(frm) {
        // Generate Employees button
        if (frm.is_new() || frm.doc.employee_details.length === 0) {
            frm.add_custom_button('Generate Employee List', function() {
                if (!frm.doc.attendance_finalised) {
                    frappe.msgprint({
                        title: 'Attendance Not Finalised',
                        message: 'Please check Attendance Finalised before generating payroll.',
                        indicator: 'red'
                    });
                    return;
                }
                if (!frm.doc.month || !frm.doc.year) {
                    frappe.msgprint({
                        title: 'Missing Info',
                        message: 'Please fill Month and Year first.',
                        indicator: 'red'
                    });
                    return;
                }
                frm.save().then(() => {
                    frappe.msgprint({
                        title: 'Success',
                        message: 'Employee list generated successfully!',
                        indicator: 'green'
                    });
                    frm.reload_doc();
                });
            });
        }

        // Show payroll summary
        if (frm.doc.total_employees > 0) {
            frm.dashboard.add_comment(
                `Total Employees: ${frm.doc.total_employees} | Total Net Payable: ₹${frm.doc.total_net_payable}`,
                'blue',
                true
            );
        }

        // Send salary slips button - only when Approved
        if (frm.doc.status === 'Approved') {
            frm.add_custom_button('Send Salary Slips', function() {
                frappe.confirm(
                    'Send salary slip emails to all employees?',
                    function() {
                        frappe.call({
                            method: 'frappe.client.get',
                            args: { doctype: 'Monthly Payroll Run', name: frm.docname },
                            callback: function(r) {
                                frappe.msgprint({
                                    title: 'Emails Queued',
                                    message: 'Salary slip emails will be sent to all employees shortly.',
                                    indicator: 'green'
                                });
                            }
                        });
                    }
                );
            });
        }
    },

    attendance_finalised: function(frm) {
        if (frm.doc.attendance_finalised) {
            frappe.show_alert({
                message: 'Attendance marked as finalised. You can now generate the employee list.',
                indicator: 'green'
            }, 5);
        }
    }
});
